input.command:
agent-browser eval "(() => {
  const text = (sel) => {
    const el = document.querySelector(sel);
    return el ? el.textContent.trim() : null;
  };
  const title = text('#productTitle') || text('h1 span#title') || text('h1 span');
  const price = text('#priceblock_ourprice') || text('#priceblock_dealprice') || text('#priceblock_saleprice') || text('#corePriceDisplay_desktop_feature_div .a-offscreen') || text('span.a-price .a-offscreen');
  const rating = text('span[data-hook="rating-out-of-text"]') || text('#acrPopover') || text('i.a-icon-star span');
  const reviews = text('#acrCustomerReviewText') || text('span[data-hook="total-review-count"]');
  const delivery = text('#mir-layout-DELIVERY_BLOCK-slot-PRIMARY_DELIVERY_MESSAGE_LARGE span') || text('#deliveryMessageMirId') || text('#deliveryMessageMirId span') || text('#mir-layout-DELIVERY_BLOCK-slot-PRIMARY_DELIVERY_MESSAGE_LARGE') || text('#mir-layout-DELIVERY_BLOCK-slot-PRIMARY_DELIVERY_MESSAGE') || text('#deliveryBlockMessage');
  return { title, price, rating, reviews, delivery };
})()"
